const item = $input.first().json;
const curso = item.curso || 'Sin curso';
const eventos = item.eventos_semana || 'No hay eventos programados para la proxima semana.';
const avisos = item.avisos_tutor || '';

const hoy = new Date();
const lunes = new Date(hoy);
lunes.setDate(hoy.getDate() + 3);
const viernes = new Date(lunes);
viernes.setDate(lunes.getDate() + 4);

const formatFecha = (d) => `${d.getDate()}/${d.getMonth()+1}/${d.getFullYear()}`;
const semana = `${formatFecha(lunes)} al ${formatFecha(viernes)}`;

let cuerpo = `BOLETIN SEMANAL - ${curso}\n`;
cuerpo += `Semana del ${semana}\n`;
cuerpo += `${'='.repeat(50)}\n\n`;
cuerpo += `PROXIMOS EVENTOS Y ACTIVIDADES:\n${eventos}\n\n`;

if (avisos) {
  cuerpo += `AVISOS DEL TUTOR/A:\n${avisos}\n\n`;
}

cuerpo += `---\nEste boletin se genera automaticamente cada viernes.\nSi tiene alguna consulta, responda a este email o contacte con el tutor/a de ${curso}.`;

return [{ json: {
  email_grupo: item.email_grupo,
  asunto: `Boletin semanal ${curso} - Semana ${semana}`,
  cuerpo,
  curso
}}];
